blocks.body:
{
    "level": "A2–B2",
    "intro": "Na tej stronie zebraliśmy <strong>najczęstsze błędy</strong> popełniane przy stronie biernej. Zwróć uwagę zwłaszcza na czasownik <strong>be</strong>, formę <strong>V3</strong> i kolejność słów w pytaniach.",
    "rules": [
        {
            "label": "be + V3",
            "color": "emerald",
            "text": "W stronie biernej potrzebujesz konstrukcji <strong>be + V3</strong>.",
            "example": "The letter is written. ✅ (nie: The letter written. ❌)"
        },
        {
            "label": "V3, nie V2",
            "color": "rose",
            "text": "Po <strong>be</strong> używamy <strong>V3</strong>, a nie formy przeszłej V2.",
            "example": "The window was broken. ✅ (nie: The window was broke. ❌)"
        },
        {
            "label": "Bez do / does / did",
            "color": "blue",
            "text": "W pytaniach biernych nie dodajemy <strong>do / does / did</strong>.",
            "example": "Is the letter written? ✅ (nie: Does the letter is written? ❌)"
        }
    ]
}

{
    "title": "1. Błędy z czasownikiem be",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie czasownika be.",
            "wrong": "The letter written yesterday.",
            "right": "✅ The letter was written yesterday."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Zła forma be w czasie teraźniejszym.",
            "wrong": "The letters is sent every day.",
            "right": "✅ The letters are sent every day."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zła forma be w czasie przeszłym.",
            "wrong": "The windows was broken.",
            "right": "✅ The windows were broken."
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Brak been w formie perfect.",
            "wrong": "The work has done.",
            "right": "✅ The work has been done."
        }
    ]
}

{
    "title": "2. Błędy z V3",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Użycie V1 zamiast V3.",
            "wrong": "English is speak here.",
            "right": "✅ English is spoken here."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie V2 zamiast V3.",
            "wrong": "The window was broke.",
            "right": "✅ The window was broken."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zła forma czasownika nieregularnego.",
            "wrong": "The book was writed by him.",
            "right": "✅ The book was written by him."
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Użycie -ing zamiast V3.",
            "wrong": "The letter is writing now.",
            "right": "✅ The letter is being written now."
        }
    ]
}

{
    "title": "3. Błędy w pytaniach",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Dodawanie do / does / did.",
            "wrong": "Does the letter is written?",
            "right": "✅ Is the letter written?"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Brak inwersji.",
            "wrong": "The letter is written?",
            "right": "✅ Is the letter written?"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zły szyk w pytaniach wh-.",
            "wrong": "Where the book was found?",
            "right": "✅ Where was the book found?"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Niepoprawna krótka odpowiedź.",
            "wrong": "Was the work done? — Yes, it done.",
            "right": "✅ Was the work done? — Yes, it was."
        }
    ]
}

{
    "title": "4. Błędy w przeczeniach",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak not przy be.",
            "wrong": "The letter is write.",
            "right": "✅ The letter is not written."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie don't / doesn't zamiast przeczenia be.",
            "wrong": "The work doesn't finished.",
            "right": "✅ The work isn't finished."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Niepoprawna forma przeczenia.",
            "wrong": "The letter is no written.",
            "right": "✅ The letter is not written."
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Brak been w przeczeniu perfect.",
            "wrong": "The work hasn't done.",
            "right": "✅ The work hasn't been done."
        }
    ]
}

{
    "title": "5. Błędy z by i with",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Użycie with zamiast by do wykonawcy.",
            "wrong": "The book was written with Shakespeare.",
            "right": "✅ The book was written by Shakespeare."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie by zamiast with do narzędzia.",
            "wrong": "The letter was written by a pen.",
            "right": "✅ The letter was written with a pen."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zbędne by + agent.",
            "wrong": "My car was stolen by someone.",
            "right": "✅ My car was stolen."
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Nienaturalny szyk z by + agent.",
            "wrong": "By the team the report was prepared.",
            "right": "✅ The report was prepared by the team."
        }
    ]
}

{
    "title": "6. Poprawne przykłady",
    "sections": [
        {
            "label": "Present Simple Passive",
            "color": "emerald",
            "description": "<strong>am / is / are + V3</strong>",
            "examples": [
                {
                    "en": "English is spoken in many countries.",
                    "ua": "W wielu krajach mówi się po angielsku."
                },
                {
                    "en": "The office is cleaned every day.",
                    "ua": "Biuro jest sprzątane codziennie."
                },
                {
                    "en": "Cars are made in Germany.",
                    "ua": "Samochody są produkowane w Niemczech."
                }
            ]
        },
        {
            "label": "Past Simple Passive",
            "color": "blue",
            "description": "<strong>was / were + V3</strong>",
            "examples": [
                {
                    "en": "The letter was sent yesterday.",
                    "ua": "List został wysłany wczoraj."
                },
                {
                    "en": "The house was built in 1990.",
                    "ua": "Dom został zbudowany w 1990 roku."
                },
                {
                    "en": "The windows were broken during the storm.",
                    "ua": "Podczas burzy wybito szyby."
                }
            ]
        },
        {
            "label": "Present Perfect Passive",
            "color": "amber",
            "description": "<strong>has / have been + V3</strong>",
            "examples": [
                {
                    "en": "The work has been completed.",
                    "ua": "Praca została ukończona."
                },
                {
                    "en": "All tickets have been sold.",
                    "ua": "Wszystkie bilety zostały sprzedane."
                },
                {
                    "en": "The report has been submitted.",
                    "ua": "Raport został złożony."
                }
            ]
        },
        {
            "label": "Modal Passive",
            "color": "rose",
            "description": "<strong>modal + be + V3</strong>",
            "examples": [
                {
                    "en": "The task must be done today.",
                    "ua": "To zadanie musi zostać wykonane dzisiaj."
                },
                {
                    "en": "This problem can be solved.",
                    "ua": "Ten problem można rozwiązać."
                },
                {
                    "en": "The report should be checked carefully.",
                    "ua": "Raport należy dokładnie sprawdzić."
                }
            ]
        }
    ]
}

{
    "title": "7. Zamiana active → passive",
    "intro": "Sprawdź, jak wygląda poprawna przebudowa zdania czynnego na bierne:",
    "rows": [
        {
            "en": "Active: Tom writes letters.",
            "ua": "Tom pisze listy.",
            "note": "→ Passive: Letters are written by Tom."
        },
        {
            "en": "Active: She cleaned the room.",
            "ua": "Posprzątała pokój.",
            "note": "→ Passive: The room was cleaned."
        },
        {
            "en": "Active: They have finished the project.",
            "ua": "Skończyli projekt.",
            "note": "→ Passive: The project has been finished."
        },
        {
            "en": "Active: Someone must do this work.",
            "ua": "Ktoś musi wykonać tę pracę.",
            "note": "→ Passive: This work must be done."
        }
    ],
    "warning": "📌 W stronie biernej dopełnienie zdania czynnego staje się nowym podmiotem."
}

{
    "title": "8. Lista kontrolna",
    "intro": "Przed zaakceptowaniem zdania sprawdź te punkty:",
    "items": [
        {
            "label": "✓ 1",
            "title": "Czy w zdaniu jest be?",
            "subtitle": "np. is / are / was / were / been"
        },
        {
            "label": "✓ 2",
            "title": "Czy forma be zgadza się z czasem i podmiotem?",
            "subtitle": "is dla liczby pojedynczej, are dla mnogiej; was / were w przeszłości"
        },
        {
            "label": "✓ 3",
            "title": "Czy po be stoi V3?",
            "subtitle": "written, broken, done, built"
        },
        {
            "label": "✓ 4",
            "title": "Czy szyk pytania jest poprawny?",
            "subtitle": "Is the letter written? / Where was it found?"
        },
        {
            "label": "✓ 5",
            "title": "Czy przeczenie stoi przy be?",
            "subtitle": "is not written / hasn't been done"
        },
        {
            "label": "✓ 6",
            "title": "Czy by / with zostało użyte poprawnie?",
            "subtitle": "by + wykonawca; with + narzędzie"
        }
    ]
}
